from pathlib import Path

root = Path('/home/ubuntu/jimmi-fit-recovery')

# Onboarding validation, scroll-to-top, placeholder, and gender options.
p = root / 'client/src/pages/Onboarding.tsx'
s = p.read_text()
s = s.replace('const genderOptions = ["Female", "Male", "Non-binary", "Prefer to self-describe", "Prefer not to say"];', 'const genderOptions = ["Male", "Female"];')
s = s.replace('function cleanOtherDetail(value: string) {\n  return value.trim().replace(/\\s*,\\s*/g, "; ");\n}\n', '''function cleanOtherDetail(value: string) {\n  return value.trim().replace(/\\s*,\\s*/g, "; ");\n}\n\nfunction calculateBirthdayAge(birthday: string, today = new Date()) {\n  const birthDate = new Date(`${birthday}T00:00:00.000Z`);\n  if (Number.isNaN(birthDate.getTime())) return null;\n  let age = today.getUTCFullYear() - birthDate.getUTCFullYear();\n  const monthDelta = today.getUTCMonth() - birthDate.getUTCMonth();\n  if (monthDelta < 0 || (monthDelta === 0 && today.getUTCDate() < birthDate.getUTCDate())) age -= 1;\n  return age;\n}\n\nfunction latestBirthdayForMinimumAge(minimumAge: number) {\n  const today = new Date();\n  const latest = new Date(Date.UTC(today.getUTCFullYear() - minimumAge, today.getUTCMonth(), today.getUTCDate()));\n  return latest.toISOString().slice(0, 10);\n}\n\nconst minimumBirthday = latestBirthdayForMinimumAge(8);\nconst birthdaySample = "2014-05-09";\n''')
s = s.replace('  const progress = Math.round(((step + 1) / steps.length) * 100);\n', '''  const previousStepRef = useRef(step);\n  const progress = Math.round(((step + 1) / steps.length) * 100);\n\n  useEffect(() => {\n    if (previousStepRef.current === step || typeof window === "undefined") return;\n    previousStepRef.current = step;\n    window.requestAnimationFrame(() => {\n      window.scrollTo({ top: 0, behavior: "smooth" });\n    });\n  }, [step]);\n''')
s = s.replace('      if (!form.name.trim()) nextErrors.name = "Name is required.";\n      if (!form.birthday) nextErrors.birthday = "Date of birth is required.";\n      if (!form.gender.trim()) nextErrors.gender = "Gender is required.";\n', '''      if (form.name.trim().length < 2) nextErrors.name = "First name must be at least 2 characters.";\n      if (!form.birthday) nextErrors.birthday = "Date of birth is required.";\n      else if (calculateBirthdayAge(form.birthday) === null) nextErrors.birthday = "Enter a valid date of birth.";\n      else if ((calculateBirthdayAge(form.birthday) ?? 0) < 8) nextErrors.birthday = "You must be at least 8 years old to use JIMMI.";\n      if (!genderOptions.includes(form.gender.trim())) nextErrors.gender = "Select Male or Female.";\n''')
s = s.replace('<Field label="Name" error={errors.name}><TextInput value={form.name} onChange={(event) => update("name", event.target.value)} placeholder="Alex Morgan" /></Field>', '<Field label="First name" error={errors.name}><TextInput value={form.name} onChange={(event) => update("name", event.target.value)} placeholder="Alex" minLength={2} /></Field>')
s = s.replace('<Field label="Date of Birth" error={errors.birthday} hint="JIMMI stores this securely to keep your profile age current automatically."><TextInput type="date" value={form.birthday} onChange={(event) => update("birthday", event.target.value)} /></Field>', '<Field label="Date of Birth" error={errors.birthday} hint="JIMMI stores this securely to keep your profile age current automatically. You must be at least 8 years old."><TextInput type="date" value={form.birthday} onChange={(event) => update("birthday", event.target.value)} placeholder={birthdaySample} max={minimumBirthday} /></Field>')
s = s.replace('["Name", form.name], ["Gender", form.gender],', '["First name", form.name], ["Gender", form.gender],')
p.write_text(s)

# Schema avatar URL.
