s = s.replace('  additionalInfo: text("additionalInfo"),\n  tourSeen: boolean("tourSeen").default(false).notNull(),', '  additionalInfo: text("additionalInfo"),\n  avatarUrl: text("avatarUrl"),\n  tourSeen: boolean("tourSeen").default(false).notNull(),')
p.write_text(s)

# Database avatar helper and persistence in updates.
p = root / 'server/db.ts'
s = p.read_text()
s = s.replace('      additionalInfo: values.additionalInfo,\n      updatedAt: new Date(),', '      additionalInfo: values.additionalInfo,\n      avatarUrl: values.avatarUrl ?? null,\n      updatedAt: new Date(),')
s = s.replace('export async function markJimmiTourSeen(userId: number) {', '''export async function updateJimmiProfileAvatar(userId: number, avatarUrl: string) {\n  const db = await getDb();\n  if (!db) return undefined;\n  await db.update(jimmiProfiles).set({ avatarUrl, updatedAt: new Date() }).where(eq(jimmiProfiles.userId, userId));\n  return getJimmiProfile(userId);\n}\n\nexport async function markJimmiTourSeen(userId: number) {''')
