s = p.read_text()
s = s.replace('import { LogOut, Menu, Salad, UserRound, Dumbbell } from "lucide-react";', 'import { Apple, LogOut, Salad, UserRound, Dumbbell } from "lucide-react";')
s = s.replace('  memberName?: string | null;\n  isLocalFallback?: boolean;', '  memberName?: string | null;\n  avatarUrl?: string | null;\n  isLocalFallback?: boolean;')
s = s.replace('export function MemberMenu({ memberName, isLocalFallback = false }: MemberMenuProps) {', 'export function MemberMenu({ memberName, avatarUrl, isLocalFallback = false }: MemberMenuProps) {')
s = s.replace('        <Button variant="outline" className="rounded-full border-white/10 bg-white/[0.03] px-4 py-2 text-muted-foreground hover:border-primary hover:text-primary">\n          <Menu className="mr-2 size-4" />\n          {memberName ? memberName : "Member"}\n        </Button>', '''        <Button variant="outline" aria-label="Open member navigation" className="size-11 rounded-full border-white/10 bg-white/[0.03] p-0 text-muted-foreground hover:border-primary hover:text-primary" data-member-menu-trigger="avatar">\n          {avatarUrl ? (\n            <img src={avatarUrl} alt="Profile avatar" className="size-full rounded-full object-cover" />\n          ) : (\n            <span className="grid size-full place-items-center rounded-full bg-[radial-gradient(circle_at_35%_25%,rgba(143,232,216,0.34),rgba(255,255,255,0.06)_45%,rgba(0,0,0,0.22))] font-mono text-xs uppercase tracking-[0.14em] text-primary">{(memberName || "J").slice(0, 1)}</span>\n          )}\n        </Button>''')
s = s.replace('<DropdownMenuLabel className="font-mono text-[0.65rem] uppercase tracking-[0.22em] text-primary">Member Menu</DropdownMenuLabel>', '<DropdownMenuLabel className="font-mono text-[0.65rem] uppercase tracking-[0.22em] text-primary">Member Menu</DropdownMenuLabel>')
s = s.replace('          <Link href="/profile"><UserRound className="size-4" /> View Profile</Link>', '          <Link href="/profile"><UserRound className="size-4" /> My Profile</Link>')
s = s.replace('        <DropdownMenuItem asChild className="cursor-pointer rounded-xl">\n          <Link href="/meal-plan#macros"><Salad className="size-4" /> View Macros</Link>\n        </DropdownMenuItem>\n', '        <DropdownMenuItem asChild className="cursor-pointer rounded-xl">\n          <Link href="/food-log"><Apple className="size-4" /> Food Log</Link>\n        </DropdownMenuItem>\n        <DropdownMenuItem asChild className="cursor-pointer rounded-xl">\n          <Link href="/meal-plan#macros"><Salad className="size-4" /> View Macros</Link>\n        </DropdownMenuItem>\n')
