# Profile photo capture UI and local/auth update handling.
p = root / 'client/src/pages/Profile.tsx'
s = p.read_text()
s = s.replace('import { CheckCircle2, Loader2, Save } from "lucide-react";', 'import { Camera, CheckCircle2, Loader2, Save } from "lucide-react";')
s = s.replace('  const [saved, setSaved] = useState(false);\n', '  const [saved, setSaved] = useState(false);\n  const [photoStatus, setPhotoStatus] = useState<string | null>(null);\n')
s = s.replace('  const updateProfile = trpc.onboarding.updateProfile.useMutation({', '''  const updateAvatar = trpc.onboarding.updateAvatar.useMutation({\n    onSuccess: async () => {\n      setPhotoStatus("Profile photo updated.");\n      await utils.onboarding.get.invalidate();\n      window.setTimeout(() => setPhotoStatus(null), 2400);\n    },\n    onError: (error) => setPhotoStatus(error.message),\n  });\n\n  const updateProfile = trpc.onboarding.updateProfile.useMutation({''')
s = s.replace('  const handleSubmit = (event: React.FormEvent<HTMLFormElement>) => {', '''  const readPhotoAsDataUrl = (file: File) => new Promise<string>((resolve, reject) => {\n    const reader = new FileReader();\n    reader.onload = () => resolve(String(reader.result));\n    reader.onerror = () => reject(new Error("Could not read that photo."));\n    reader.readAsDataURL(file);\n  });\n\n  const handlePhotoCapture = async (event: React.ChangeEvent<HTMLInputElement>) => {\n    const file = event.target.files?.[0];\n    if (!file) return;\n    setPhotoStatus("Updating profile photo...");\n    try {\n      const imageDataUrl = await readPhotoAsDataUrl(file);\n      if (isLocalFallback) {\n        const nextProfile = { ...(profile ?? {}), avatarUrl: imageDataUrl };\n        window.localStorage.setItem(LOCAL_PROFILE_KEY, JSON.stringify(nextProfile));\n        setLocalProfile(nextProfile);\n        setPhotoStatus("Profile photo updated on this device.");\n        window.setTimeout(() => setPhotoStatus(null), 2400);\n        return;\n      }\n      updateAvatar.mutate({ imageDataUrl });\n    } catch (error) {\n      setPhotoStatus(error instanceof Error ? error.message : "Could not update that photo.");\n    } finally {\n      event.target.value = "";\n    }\n  };\n\n  const handleSubmit = (event: React.FormEvent<HTMLFormElement>) => {''')
s = s.replace('<MemberMenu memberName={profile.firstName} isLocalFallback={isLocalFallback} />', '<MemberMenu memberName={profile.firstName} avatarUrl={profile.avatarUrl} isLocalFallback={isLocalFallback} />')
s = s.replace('            <div>\n              <p className="font-mono text-xs uppercase tracking-[0.28em] text-primary">My Profile</p>', '''            <div className="flex flex-col gap-5 sm:flex-row sm:items-center">\n              <div className="relative size-24 shrink-0 overflow-hidden rounded-full border border-white/10 bg-white/[0.04] shadow-2xl shadow-black/40">\n                {profile.avatarUrl ? <img src={profile.avatarUrl} alt="Profile avatar" className="size-full object-cover" /> : <div className="grid size-full place-items-center bg-[radial-gradient(circle_at_35%_25%,rgba(143,232,216,0.30),rgba(255,255,255,0.05)_48%,rgba(0,0,0,0.3))] font-display text-4xl text-primary">{String(profile.firstName || "J").slice(0, 1)}</div>}\n              </div>\n              <div>\n                <p className="font-mono text-xs uppercase tracking-[0.28em] text-primary">My Profile</p>''')
s = s.replace('              <p className="mt-5 max-w-2xl text-muted-foreground">Edit your onboarding data here. Saved changes synchronize back to the profile context JIMMI uses in Chat.{isLocalFallback ? " Preview changes are saved locally on this device until you sign in." : ""}</p>\n            </div>', '                <p className="mt-5 max-w-2xl text-muted-foreground">Edit your onboarding data here. Saved changes synchronize back to the profile context JIMMI uses in Chat.{isLocalFallback ? " Preview changes are saved locally on this device until you sign in." : ""}</p>\n              </div>\n            </div>')
s = s.replace('              {saved ? <span className="inline-flex items-center gap-2 rounded-full border border-primary/30 bg-primary/10 px-4 py-2 text-sm text-primary"><CheckCircle2 className="size-4" /> Saved</span> : null}\n              <Button disabled={!isLocalFallback && updateProfile.isPending} className="rounded-full bg-primary text-primary-foreground">', '''              <label className="inline-flex cursor-pointer items-center gap-2 rounded-full border border-white/10 bg-white/[0.04] px-4 py-2 text-sm text-muted-foreground transition hover:border-primary hover:text-primary" data-profile-photo-capture="true">\n                <Camera className="size-4" /> Take photo\n                <input type="file" accept="image/png,image/jpeg,image/webp" capture="user" className="sr-only" onChange={handlePhotoCapture} disabled={updateAvatar.isPending} />\n              </label>\n              {photoStatus ? <span className="text-sm text-muted-foreground">{photoStatus}</span> : null}\n              {saved ? <span className="inline-flex items-center gap-2 rounded-full border border-primary/30 bg-primary/10 px-4 py-2 text-sm text-primary"><CheckCircle2 className="size-4" /> Saved</span> : null}\n              <Button disabled={!isLocalFallback && updateProfile.isPending} className="rounded-full bg-primary text-primary-foreground">''')
s = s.replace('<FormField label="Gender"><input className={inputClass} value={form.gender} onChange={(event) => updateField("gender", event.target.value)} required /></FormField>', '<FormField label="Gender"><select className={inputClass} value={form.gender} onChange={(event) => updateField("gender", event.target.value)} required><option value="">Select gender</option><option value="Male">Male</option><option value="Female">Female</option></select></FormField>')
p.write_text(s)

