# Add a lightweight Food Log page and route.
p = root / 'client/src/pages/FoodLog.tsx'
p.write_text('''import { useEffect, useState } from "react";\nimport { Link } from "wouter";\nimport { Apple, Loader2, Plus, Utensils } from "lucide-react";\nimport { Button } from "@/components/ui/button";\nimport { MemberMenu } from "@/components/MemberMenu";\nimport { useAuth } from "@/_core/hooks/useAuth";\nimport { trpc } from "@/lib/trpc";\n\nconst LOCAL_PROFILE_KEY = "jimmi-local-onboarding-profile";\n\nfunction readLocalOnboardingProfile() {\n  if (typeof window === "undefined") return null;\n  try {\n    const rawProfile = window.localStorage.getItem(LOCAL_PROFILE_KEY);\n    return rawProfile ? JSON.parse(rawProfile) : null;\n  } catch {\n    return null;\n  }\n}\n\nexport default function FoodLog() {\n  const { user, loading } = useAuth({ redirectOnUnauthenticated: false });\n  const [localProfile] = useState<any>(() => readLocalOnboardingProfile());\n  const profileQuery = trpc.onboarding.get.useQuery(undefined, { enabled: Boolean(user), retry: false });\n  const profile = profileQuery.data ?? localProfile;\n  const isLocalFallback = !user && Boolean(localProfile);\n\n  if (loading || (Boolean(user) && profileQuery.isLoading)) {\n    return (\n      <main className="min-h-screen bg-background text-foreground">\n        <section className="container flex min-h-screen items-center justify-center">\n          <div className="rounded-3xl border border-white/10 bg-card p-8 text-center">\n            <Loader2 className="mx-auto size-8 animate-spin text-primary" />\n            <p className="mt-4 text-muted-foreground">Loading your food log...</p>\n          </div>\n        </section>\n      </main>\n    );\n  }\n\n  if (!profile) {\n    return (\n      <main className="min-h-screen bg-background text-foreground">\n        <section className="container flex min-h-screen items-center py-16">\n          <div className="max-w-2xl rounded-[2rem] border border-white/10 bg-card p-8">\n            <p className="font-mono text-xs uppercase tracking-[0.28em] text-primary">Food Log</p>\n            <h1 className="mt-4 font-display text-5xl font-light tracking-tight">Complete onboarding first</h1>\n            <p className="mt-4 text-muted-foreground">JIMMI uses your profile baseline to make food logging more useful.</p>\n            <Link href="/onboarding"><Button className="mt-8 rounded-full bg-primary text-primary-foreground">Start onboarding</Button></Link>\n          </div>\n        </section>\n      </main>\n    );\n  }\n\n  return (\n    <main className="min-h-screen bg-background text-foreground">\n      <section className="container py-8 md:py-12">\n        <header className="flex flex-wrap items-center justify-between gap-4 border-b border-white/10 pb-6">\n          <Link href="/" className="font-display text-2xl font-light tracking-[0.24em]">JIMMI</Link>\n          <nav className="flex items-center gap-3 text-sm">\n            <Link href="/chat" className="rounded-full border border-white/10 px-4 py-2 text-muted-foreground hover:border-primary hover:text-primary">Chat</Link>\n            <MemberMenu memberName={profile.firstName} avatarUrl={profile.avatarUrl} isLocalFallback={isLocalFallback} />\n          </nav>\n        </header>\n\n        <div className="mt-10 grid gap-6 lg:grid-cols-[0.95fr_1.05fr]">\n          <section className="rounded-[2.25rem] border border-white/10 bg-card p-6 shadow-2xl shadow-black/40 md:p-8">\n            <p className="font-mono text-xs uppercase tracking-[0.28em] text-primary">Food Log</p>\n            <h1 className="mt-4 font-display text-5xl font-light leading-none tracking-tight md:text-7xl">Log meals with JIMMI</h1>\n            <p className="mt-5 text-muted-foreground">A dedicated logging workflow is now available from the member menu. The full meal-entry builder will connect your meals, macros, allergies, and coaching feedback in a later pass.</p>\n            <Button className="mt-8 rounded-full bg-primary text-primary-foreground" onClick={() => window.alert("Meal entry builder coming soon.")}>\n              <Plus className="mr-2 size-4" /> Add meal\n            </Button>\n          </section>\n\n          <section className="rounded-[2.25rem] border border-white/10 bg-white/[0.035] p-6 md:p-8">\n            <div className="grid gap-4 sm:grid-cols-2">\n              {[\n                ["Breakfast", "Start the day with protein and hydration."],\n                ["Lunch", "Capture energy, fiber, and recovery support."],\n                ["Dinner", "Track portions and late-day nutrition."],\n                ["Snacks", "Keep hunger, cravings, and macros visible."],\n              ].map(([title, detail]) => (\n                <div key={title} className="rounded-3xl border border-white/10 bg-black/20 p-5">\n                  <div className="grid size-10 place-items-center rounded-full border border-primary/20 bg-primary/10 text-primary">\n                    {title === "Snacks" ? <Apple className="size-5" /> : <Utensils className="size-5" />}\n                  </div>\n                  <h2 className="mt-4 font-display text-2xl font-light">{title}</h2>\n                  <p className="mt-2 text-sm leading-6 text-muted-foreground">{detail}</p>\n                </div>\n              ))}\n            </div>\n          </section>\n        </div>\n      </section>\n    </main>\n  );\n}\n''')

p = root / 'client/src/App.tsx'
s = p.read_text()
s = s.replace('import MealPlan from "@/pages/MealPlan";', 'import MealPlan from "@/pages/MealPlan";\nimport FoodLog from "@/pages/FoodLog";')
